describe('find sink mutation test', () => {
  it('should handle error callback correctly when err is true', (done) => {
    const error = true;
    let callbackCalled = false;

    const callback = (err: any, data: any) => {
      callbackCalled = true;
      try {
        expect(err).toBeNull();
        expect(data).toBeNull();
        done();
      } catch (e) {
        done(e);
